}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
}

body {
  background:
    radial-gradient(circle at top left, rgba(148, 163, 184, 0.18), transparent 31rem),
    radial-gradient(circle at top right, rgba(191, 219, 254, 0.14), transparent 27rem),
    linear-gradient(180deg, #f8fafc 0%, #edf2f7 48%, #e5ebf2 100%);
  color: var(--ink);
  font-family: var(--font-body);
  font-size: var(--text-body);
  letter-spacing: -0.01em;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: none;
}

button,
input,
textarea {
  font: inherit;
}

::selection {
  background: rgba(50, 72, 99, 0.18);
}

.page-shell {
  min-height: 100vh;
  padding: var(--space-4);
}

.site-main {
  width: 100%;
}

.site-header,
.feature-layout,
.vault-shell,
.note-editor-shell {
  margin: 0 auto;
  max-width: var(--container-max);
}

.site-header {
  align-items: flex-start;
  backdrop-filter: blur(20px);
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(148, 163, 184, 0.28);
  border-radius: var(--radius-4);
  box-shadow: var(--shadow-soft);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
  padding: 0.95rem 1.05rem;
}

.brand-block,
.hero-copy,
.vault-frame-copy,
.vault-nav-block {
  display: grid;
  gap: var(--space-2);
}

.brand {
  font-family: var(--font-ui);
  font-size: 0.92rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.brand-caption,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.note-list-item p,
.panel-card p,
.feature-card p,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.section-meta,
.tag-filter-count,
.vault-frame-note {
  color: var(--ink-muted);
}

.brand-caption,
.vault-frame-note,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.note-list-item p {
  line-height: 1.65;
  margin: 0;
}

.brand-caption {
  font-size: var(--text-base);
  max-width: 36rem;
}

.site-nav,
.vault-nav,
.note-meta,
.ui-metadata-row,
.inline-list {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.site-nav a,
.vault-nav-link {
  border: 1px solid transparent;
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.12em;
  min-height: 2.8rem;
  padding: 0.72rem 1rem;
  text-transform: uppercase;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    transform 140ms ease;
}

.site-nav a:hover,
.vault-nav-link:hover,
.route-tile:hover,
.note-list-link:hover,
.tag-filter-link:hover,
.primary-button:hover,
.ghost-button:hover,
.ui-button:hover {
  transform: translateY(-1px);
}

.site-nav a:hover,
.vault-nav-link:hover {
  background: rgba(255, 255, 255, 0.82);
  border-color: var(--line);
  color: var(--ink);
}

.vault-nav-link-active {
  background: var(--accent-soft);
  border-color: var(--accent-soft-strong);
  color: var(--accent-strong);
}

.vault-nav-link {
  align-items: center;
  display: inline-flex;
  justify-content: center;
}

.feature-layout,
.note-editor-shell,
.login-layout,
.dashboard-grid,
.public-home-grid,
.link-manager-grid,
.retrieval-grid,
.route-grid,
.summary-row,
.tag-filter-list,
.detail-stack,
.ui-intro-block,
.ui-support-grid,
.ui-form-stack,
.note-editor-grid,
.link-form,
.link-list,
.link-list-item,
.link-list-heading,
.link-list-footer,
.tag-list,
.ui-tag-list,
.search-form,
.note-generated-panel,
.note-generated-copy,
.field-group,
.ui-field {
  display: grid;
  gap: var(--space-4);
}

.feature-layout,
.note-editor-shell,
.public-home-grid,
.dashboard-grid,
.login-layout,
.link-manager-grid,
.retrieval-grid,
.note-editor-grid {
  grid-template-columns: minmax(0, 1fr);
}

.ui-surface,
.hero-card,
.panel-card,
.feature-card,
.vault-frame,
.public-note-metadata {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.56), transparent 26%),
    var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius-4);
  box-shadow: var(--shadow-panel);
  position: relative;
}

.ui-surface::before,
.hero-card::before,
.panel-card::before,
.feature-card::before,
.vault-frame::before,
.public-note-metadata::before {
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.9), transparent);
  content: "";
  height: 1px;
  left: var(--space-6);
  position: absolute;
  right: var(--space-6);
  top: 0;
}

.ui-surface,
.hero-card,
.panel-card,
.feature-card,
.vault-frame {
  padding: var(--space-5);
}

.ui-surface-compact {
  padding: 1rem 1.05rem 1.1rem;
}

