  --text-base: 0.95rem;
  --text-body: 1rem;
  --text-lg: 1.08rem;
  --text-xl: 1.28rem;
  --text-2xl: clamp(1.75rem, 3.8vw, 2.55rem);
  --text-display: clamp(1.95rem, 5vw, 3.35rem);
  --measure: 65ch;
  --container-max: 84rem;
  --font-display: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-body: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-ui: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-mono: "IBM Plex Mono", "SFMono-Regular", Menlo, Consolas, monospace;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;

}

.route-tile {
  display: grid;
  gap: 0.4rem;
}

.route-tile strong {
  margin-bottom: 0;
}

.route-tile span {
  color: var(--ink-muted);
  line-height: 1.6;
}

.search-form {
  align-items: end;
}

.markdown-preview {
  border-top: 1px solid var(--line);
  color: var(--ink-soft);
  margin-top: var(--space-4);
  padding-top: var(--space-5);
}

.markdown-preview > :first-child {
  margin-top: 0;
}

.markdown-preview > :last-child {
  margin-bottom: 0;
}

.markdown-preview h1,
.markdown-preview h2,
.markdown-preview h3,
.markdown-preview h4,
.markdown-preview h5,
.markdown-preview h6 {
  color: var(--ink);
  font-family: var(--font-display);
  font-weight: 650;
  letter-spacing: -0.03em;
  line-height: 1.08;
  margin: 1.45rem 0 0.7rem;
}

.markdown-preview h1 {
  font-size: 1.85rem;
}

.markdown-preview h2 {
  font-size: 1.52rem;
}

}

.dashboard-note-ai {
  gap: 0.25rem;
}

.dashboard-note-ai strong {
  display: block;
  font-family: var(--font-ui);
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  margin-bottom: 0;
  text-transform: uppercase;
}

.dashboard-note-ai-summary {
  -webkit-line-clamp: 2;
  font-size: var(--text-sm);
  line-height: 1.42;
}

.dashboard-note-ai-empty,
.dashboard-note-ai-detail {
  font-size: 0.75rem;
  line-height: 1.4;
}

.dashboard-note-tags {
  gap: 0.35rem;
  grid-template-columns: repeat(auto-fit, minmax(4.5rem, max-content));
}

.dashboard-note-tags .tag-pill,
.dashboard-note-tags .ui-tag {
  background: rgba(50, 72, 99, 0.05);
  border-color: rgba(50, 72, 99, 0.11);
  color: var(--ink-muted);
  font-size: 0.64rem;
  min-height: 1.6rem;
  padding: 0.16rem 0.52rem;
}

.dashboard-route-grid {
  gap: 0.75rem;
}

.dashboard-route-grid .route-tile {
  gap: 0.3rem;
  padding: 0.95rem 1rem;
}

.dashboard-route-grid .route-tile span {
  font-size: var(--text-sm);
  line-height: 1.5;
}

.secondary-route-hero,
.secondary-route-grid,
.secondary-summary-grid,
.secondary-list-panel,
.secondary-control-panel,
.secondary-filter-panel,
.secondary-search-form,
.secondary-search-controls,
.secondary-link-item,
.secondary-link-main,
.secondary-link-meta {
  display: grid;
}

.secondary-route-hero {
  gap: var(--space-4);
  overflow: hidden;
}

.secondary-route-hero .ui-intro-block h1 {
  font-size: clamp(1.45rem, 2.8vw, 2rem);
  line-height: 0.98;
  max-width: 13ch;
}

.secondary-route-hero .ui-intro-block .lede {
  font-size: var(--text-sm);
  line-height: 1.55;
  max-width: 34rem;
}

.secondary-summary-grid {
  gap: 0.7rem;

}

.dashboard-hero-copy {
  gap: var(--space-2);
}

.dashboard-hero .dashboard-hero-title {
  font-size: clamp(1.55rem, 2.8vw, 2.15rem);
  line-height: 0.98;
  letter-spacing: -0.035em;
  margin: 0;
  max-width: 14ch;
}

.dashboard-hero-lede {
  font-size: var(--text-sm);
  line-height: 1.55;
  max-width: 35rem;
}

.dashboard-hero-actions {
  align-content: start;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  margin-top: 0;
}

.dashboard-summary-row {
  gap: 0.7rem;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  margin-top: 0;
  padding-top: 0.75rem;
}

.dashboard-stat {
  align-content: start;
  background: rgba(248, 250, 252, 0.84);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: var(--radius-2);
  gap: 0.18rem;
  min-width: 0;
  padding: 0.72rem 0.78rem;
}

.dashboard-stat strong {
  display: block;
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.14em;
  margin-bottom: 0.05rem;
  text-transform: uppercase;
}

.dashboard-stat-value {
  color: var(--accent-strong);
  font-family: var(--font-display);
  font-size: clamp(1.2rem, 2.3vw, 1.6rem);
  line-height: 1;
}

.dashboard-stat span:last-child {
  color: var(--ink-muted);
  display: none;
  font-size: 0.78rem;
  line-height: 1.4;
}

.public-side-panel,
.dashboard-side-panel,
.login-form-card {
  align-self: start;
}

.public-hero,
.note-editor-intro {
  overflow: hidden;
}

.public-home-shell-head,
.public-home-shell-copy {
  display: grid;
  gap: var(--space-4);
}

.public-home-shell-head {
  border-bottom: 1px solid var(--line);
  gap: var(--space-3);
  padding-bottom: var(--space-4);
}

.public-home-shell-copy {
  gap: var(--space-2);
}

.public-home-count {
