158	async function expectReadingHierarchy(page: Page, viewport: "desktop" | "mobile") {
159	  const metrics = await page.evaluate(() => {
160	    const heading = document.querySelector(".public-note-header h1");
161	    const body = document.querySelector("[data-testid='public-note-markdown']");
162	    const bodyMeasure = body?.querySelector("p, ul, ol, blockquote, h2, h3");
163	    const support = document.querySelector("[data-testid='public-note-support']");
164	    const meta = document.querySelector(".public-note-meta");
165	
166	    if (!heading || !body || !bodyMeasure || !support || !meta) {
167	      throw new Error("Public note hierarchy anchors are missing.");
168	    }
169	
170	    const headingRect = heading.getBoundingClientRect();
171	    const bodyRect = body.getBoundingClientRect();
172	    const bodyMeasureRect = bodyMeasure.getBoundingClientRect();
173	    const supportRect = support.getBoundingClientRect();
174	    const metaRect = meta.getBoundingClientRect();
175	
176	    return {
177	      bodyMeasureWidth: Math.round(bodyMeasureRect.width),
178	      bodyTop: Math.round(bodyRect.top),
179	      headingTop: Math.round(headingRect.top),
180	      metaTop: Math.round(metaRect.top),
181	      supportTop: Math.round(supportRect.top),
182	      viewportWidth: document.documentElement.clientWidth
183	    };
184	  });
185	
186	  expect(metrics.metaTop).toBeLessThan(metrics.headingTop);
187	  expect(metrics.headingTop).toBeLessThan(metrics.bodyTop);
188	  expect(metrics.bodyTop).toBeLessThan(metrics.supportTop);
189	  expect(metrics.bodyMeasureWidth).toBeLessThanOrEqual(viewport === "desktop" ? 760 : metrics.viewportWidth - 32);
190	}
