192	async function expectSoftenedPublicType(page: Page, viewport: "desktop" | "mobile") {
193	  const styles = await page.evaluate(() => {
194	    const heading = document.querySelector(".public-note-header h1");
195	    const bodyParagraph = document.querySelector("[data-testid='public-note-markdown'] p");
196	    const supportStrong = document.querySelector("[data-testid='public-note-support'] strong");
197	
198	    if (!heading || !bodyParagraph || !supportStrong) {
199	      return null;
200	    }
201	
202	    return {
203	      bodySize: Number.parseFloat(getComputedStyle(bodyParagraph).fontSize),
204	      headingSize: Number.parseFloat(getComputedStyle(heading).fontSize),
205	      supportStrongColor: getComputedStyle(supportStrong).color,
206	      supportStrongSize: Number.parseFloat(getComputedStyle(supportStrong).fontSize)
207	    };
208	  });
209	
210	  expect(styles).not.toBeNull();
211	
212	  if (!styles) {
213	    return;
214	  }
215	
216	  expect(styles.headingSize).toBeGreaterThan(styles.bodySize + (viewport === "desktop" ? 12 : 9));
217	  expect(styles.headingSize).toBeLessThan(viewport === "desktop" ? 35 : 32);
218	  expect(styles.supportStrongSize).toBeLessThan(styles.bodySize);
219	  expect(styles.supportStrongColor).toBe("rgb(51, 65, 85)");
220	}
